def first_and_last_position(nums, target):
    def bound(left_bias):
        left, right = 0, len(nums)
        while left < right:
            mid = (left + right) // 2
            if nums[mid] > target or (left_bias and nums[mid] == target):
                right = mid
            else:
                left = mid + 1
        return left
    left_idx = bound(True)
    if left_idx == len(nums) or (left_idx < len(nums) and nums[left_idx] != target):
        return [-1, -1]
    right_idx = bound(False) - 1
    return [left_idx, right_idx]

